import java.math.BigInteger;

public class RSDAecoder {

    // Function to compute the modular inverse using the Extended Euclidean Algorithm
    public static BigInteger modInverse(BigInteger a, BigInteger m) {
        if (m.compareTo(BigInteger.ZERO) <= 0) {
            throw new ArithmeticException("Modulus must be positive");
        }

        BigInteger[] result = extendedGCD(a, m);
        if (!result[0].equals(BigInteger.ONE)) {
            throw new ArithmeticException("No modular inverse exists");
        }
        // Ensure the result is positive
        return result[1].mod(m).add(m).mod(m);
    }

    // Extended Euclidean Algorithm
    private static BigInteger[] extendedGCD(BigInteger a, BigInteger b) {
        BigInteger[] result = new BigInteger[]{a, BigInteger.ONE, BigInteger.ZERO};
        BigInteger[] newResult = new BigInteger[]{b, BigInteger.ZERO, BigInteger.ONE};

        while (!newResult[0].equals(BigInteger.ZERO)) {
            BigInteger quotient = result[0].divide(newResult[0]);
            BigInteger temp = newResult[0];
            newResult[0] = result[0].subtract(quotient.multiply(newResult[0]));
            result[0] = temp;
            temp = newResult[1];
            newResult[1] = result[1].subtract(quotient.multiply(newResult[1]));
            result[1] = temp;
            temp = newResult[2];
            newResult[2] = result[2].subtract(quotient.multiply(newResult[2]));
            result[2] = temp;
        }
        return result;
    }

    public static void main(String[] args) {
        try {
            // Given values
            String hexCiphertext = "";
            BigInteger n = new BigInteger("");
            BigInteger e = new BigInteger("65537");
            BigInteger ciphertext = new BigInteger(hexCiphertext, 16);

            // Factorize n (Assuming p and q are known for simplicity)
            // Replace these values with actual factors of n
            BigInteger p = new BigInteger("");

            BigInteger q = n.divide(p); // Calculate q by dividing n by p

            // Compute φ(n) = (p-1)(q-1)
            BigInteger phi = (p.subtract(BigInteger.ONE)).multiply(q.subtract(BigInteger.ONE));

            // Check if φ(n) is positive
            if (phi.compareTo(BigInteger.ZERO) <= 0) {
                throw new ArithmeticException("φ(n) must be positive");
            }

            // Compute the private exponent d
            BigInteger d = modInverse(e, phi);

            // Print the private exponent d
            System.out.println("Private exponent d: " + d);

            // Decrypt the ciphertext: plaintext = ciphertext^d mod n
            BigInteger plaintext = ciphertext.modPow(d, n);
            String decryptedText = new String(plaintext.toByteArray());

            // Print the decrypted plaintext
            System.out.println("Decrypted plaintext: " + decryptedText);
        } catch (ArithmeticException e) {
            System.err.println("ArithmeticException: " + e.getMessage());
        } catch (Exception e) {
            System.err.println("Exception: " + e.getMessage());
        }
    }
}
